    # Load the input image from the request body
    input_image = load_img(request.files['input_image'])
    
    # Compute the confidence scores for all training classes
    confidence_scores = compute_confidence_scores(img_to_array(input_image))
    
    # Return the confidence scores as a JSON response
    return jsonify({'confidence_scores': confidence_scores})